import BaseService from "./base-service";

const url = import.meta.env.VITE_API_URL;

export default class DetailRekapService extends BaseService {
  async getMesinById<T>(id:any): Promise<T> {
    return this.get(`${url}mesin-realisasi/${id}`);
  }
  async getPembangkitByKode<T>(kode_sentral: string): Promise<T> {
    return this.get(`${url}pembangkit/by-kode`, {kode_sentral: kode_sentral});
  }
  async getPengelolaData<T>(): Promise<T> {
    return this.get(`${url}filter/combo-pengelola-sentral`);
  }
  async getTypePeriodic<T>(kode_jenis_pembangkit:any): Promise<T> {
    return this.get(`${url}kertas-kerja-detail/type-periodic`, {kode_jenis_pembangkit: kode_jenis_pembangkit});
  }
  // Mesin
  async getAsumsiParameter<T>(tahun_realisasi:any, id_mesin:any): Promise<T> {
    return this.post(`${url}kertas-kerja-detail/asumsi-parameter`, {tahun_realisasi: tahun_realisasi, id_mesin: id_mesin});
  }
  async getDataTeknis<T>(tahun_realisasi:any, id_mesin:any): Promise<T> {
    return this.post(`${url}kertas-kerja-detail/data-teknis-final`, {tahun_realisasi: tahun_realisasi, id_mesin: id_mesin});
  }
  async getDataFinansial<T>(tahun_realisasi:any, id_mesin:any): Promise<T> {
    return this.post(`${url}kertas-kerja-detail/data-finansial-final`, {tahun_realisasi: tahun_realisasi, id_mesin: id_mesin});
  }
  async getTahunRealisasi<T>(id_mesin:any): Promise<T> {
    return this.get(`${url}kertas-kerja-detail/tahun-realisasi`, {id_mesin: id_mesin});
  }
  // Sentral
  async getSentralById<T>(id:any): Promise<T> {
    return this.get(`${url}pembangkit/${id}`);
  }
  async getAsumsiMakroSentral<T>(tahun_realisasi:any, id_sentral:any): Promise<T> {
    return this.post(`${url}kertas-kerja-detail/asumsi-parameter-sentral`, {tahun_realisasi: tahun_realisasi, id_sentral: id_sentral});
  }
  async getDataTeknisSentral<T>(tahun_realisasi:any, id_sentral:any): Promise<T> {
    return this.post(`${url}kertas-kerja-detail/data-teknis-sentral`, {tahun_realisasi: tahun_realisasi, id_sentral: id_sentral});
  }
  async getDataFinansialSentral<T>(tahun_realisasi:any, id_sentral:any): Promise<T> {
    return this.post(`${url}kertas-kerja-detail/data-finansial-sentral`, {tahun_realisasi: tahun_realisasi, id_sentral: id_sentral});
  }
}

